    if (agIsBusy())          { agSetStatus('⏸ Aguardando…');             agSchedule(AG_TICK_MS);  return; }
    if (agInventoryFull())   { agSetStatus('🎣 Inventário cheio — pausado'); agSchedule(2000);     return; }
    const eq = $n();
