        const _haPick = AG_TOOLS['rock'].some(function(t){ for(var i=0;i<Fe.length;i++){ var s=Fe[i]; if(s&&s.type===t&&(s.count||0)>0) return true; } return false; });
        if (!_haAxe && !_haPick) { agSetStatus('⚠️ Sem machado nem picareta na hotbar'); agSchedule(2000); return; }
