    function saveSellGlobalConfig(enabled) {
      var c = agLoadAutoSellConfig();
      c.enabled    = enabled !== undefined ? enabled : agAutoSellActive;
      c.intervalMs = Number($('as-interval').value) || 300000;
      agSaveAutoSellConfig(c);
    }

    // Init
    (function() {
      var cfg = agLoadAutoSellConfig();
      if (cfg.intervalMs && $('as-interval')) $('as-interval').value = String(cfg.intervalMs);
      asRenderItemList();
      if (agAutoSellActive) updateSellBtn(true);
    })();

    if ($('as-interval')) $('as-interval').addEventListener('change', function() { saveSellGlobalConfig(); });

    if ($('as-blacklist-btn')) $('as-blacklist-btn').addEventListener('click', function() { agOpenBlacklistEditor(); });
    agRenderBlacklistTags();

